import "./Login.css";
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";

function Login({ onLoginSuccess }) {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!empld || !password) {
      setError("Please enter Employee ID and Password.");
      return;
    }

    try {
      setLoading(true);

      const response = await fetch(`${apiBase}/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ empld, password }),
      });

      const data = await response.json();

      console.log("LOGIN RESPONSE:", data); // Debug

      // ⭐ FIXED LOGIN CONDITIONS (your backend does not return data.success)
      if (!response.ok || !data || !data.employee) {
        setError(data.message || "Invalid credentials");
      } else {
        // ⭐ LOGIN SUCCESS → SAVE USER + REDIRECT
        onLoginSuccess(data.employee);
        navigate("/home");
      }
    } catch (err) {
      console.error("Login Error:", err);
      setError("Server error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <img src="/logo.png" alt="PRASA Logo" className="login-logo" />
        <h2 className="login-title">PRASA Employee Portal</h2>

        <form onSubmit={handleLogin}>
          <input
            type="text"
            placeholder="Enter EMPID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
            className="input-box"
          />

          <input
            type="password"
            placeholder="Enter Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="input-box"
          />

          <button type="submit" className="btn-login" disabled={loading}>
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        {error && <p className="error-text">{error}</p>}
      </div>
    </div>
  );
}

export default Login;
